/// Look up a key in the given lang, fall back to en, then return the key itself.
pub fn t(store: &I18nStore, lang: &str, key: &str) -> String {
    store
        .get(lang)
        .and_then(|m| m.get(key).copied())
        .or_else(|| store.get("en").and_then(|m| m.get(key).copied()))
        .unwrap_or(key)
        .to_string()
}
